/* HTMX - Minimal JS for AJAX */
/* This is a placeholder. In production, download from https://htmx.org */
(function(){
    const htmx = {
        ajax: function(method, url, target) {
            fetch(url, { method })
                .then(r => r.text())
                .then(html => {
                    const el = document.querySelector(target);
                    if (el) {
                        el.innerHTML = html;
                        document.body.dispatchEvent(new CustomEvent('htmx:afterSwap', {
                            detail: { target: el }
                        }));
                    }
                });
        }
    };
    
    // Process hx-get attributes on load
    document.addEventListener('DOMContentLoaded', function() {
        document.querySelectorAll('[hx-get]').forEach(el => {
            const url = el.getAttribute('hx-get');
            const trigger = el.getAttribute('hx-trigger') || 'load';
            
            if (trigger.includes('load')) {
                fetch(url)
                    .then(r => r.text())
                    .then(html => {
                        el.innerHTML = html;
                        document.body.dispatchEvent(new CustomEvent('htmx:afterSwap', {
                            detail: { target: el }
                        }));
                    });
            }
            
            // Handle periodic refresh
            const match = trigger.match(/every\s+(\d+)s/);
            if (match) {
                const interval = parseInt(match[1]) * 1000;
                setInterval(() => {
                    fetch(url)
                        .then(r => r.text())
                        .then(html => {
                            el.innerHTML = html;
                            document.body.dispatchEvent(new CustomEvent('htmx:afterSwap', {
                                detail: { target: el }
                            }));
                        });
                }, interval);
            }
        });
    });
    
    window.htmx = htmx;
})();
